import redis
from celery import shared_task

r = redis.Redis()

@shared_task(bind=True, acks_late=True, reject_on_worker_lost=True)
def send_welcome_email(self, user_id: int):
    dedup_key = f"task:done:{self.request.id}"
    if r.get(dedup_key):
        return {"status": "skipped", "reason": "duplicate"}

    # perform side effect
    _dispatch_email(user_id)

    # mark complete with TTL matching your visibility window
    r.set(dedup_key, 1, ex=86400)
    return {"status": "sent"}

# celery_config.py
app.config_from_object({
    'broker_url': 'redis://localhost:6379/0',
    'result_backend': 'redis://localhost:6379/1',

    # Re-queue task if worker dies before this window expires
    # Must be > your longest-running task duration
    'broker_transport_options': {
        'visibility_timeout': 7200,  # 2 hours
    },

    # ACK only after task completes — safer with AOF persistence
    'task_acks_late': True,
    'task_reject_on_worker_lost': True,
})
